from robot_host import BaseModule
from robot_host.telemetry.telemetry_sections import TELEM_MY_SENSOR
class MySensorModule(BaseModule):
name = 'my_sensor'
def topics(self):
return ['telemetry.my_sensor']
def on_telemetry_my_sensor(self, data):
self.latest_value = data['value']
print(f'Sensor: {data}')
async def read(self, sensor_id: int):
return await self._robot.client.cmd_my_sensor_read(
sensor_id=sensor_id
)

📄 MySensorHandler.h
━━━━━━━━━━━━━━━━━━━━━━━━━━━
class MySensorHandler : public IStringHandler {
public:
static constexpr const char* CMDS[] = {
'CMD_MY_SENSOR_READ', nullptr
};
void handle(const char* cmd,
JsonVariantConst payload,
CommandContext& ctx) override {
int id = payload['sensor_id'];
float val = readSensor(id);
ctx.sendAck(cmd, true, {{'value', val}});
}
};
REGISTER_HANDLER(MySensorHandler);
